window.__QUIZ_DATA__=[{"id":"objective>Physics>2011>1","subject":"Physics","year":"2011","type":"Objective","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"Which of the following statement is not correct?","images":[],"options":{"A":"Molecules of ice, water and water vapour have equal intermolecular distances","B":"Molecules of ice, water and water vapour do not differ in the structure of their molecules","C":"Molecules of water vapour attract each other with forces far less than the forces of attraction between water molecules","D":"Water is less compressible than water vapour"},"answer":"A","explanation":"* Ice, water and steam exist respectively as solid, liquid and gas.    * From the studies of atom, the molecules of a solid are very closely packed and are held together by a very strong forces of attraction, the molecules of a liquid are closely packed but not like those of solids and are held together by strong forces of attractions not up to that of solid; the molecules of a gas are very far apart from one another and are held together by very weak attractive forces.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>2","subject":"Physics","year":"2011","type":"Objective","topic":"FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : DERIVED QUANTITIES AND UNITS","question":"The density p of a spherical ball of diameter d and mass m is given by","images":[],"options":{"A":"p = 3m/4\u03c0m3","B":"p = 4\u03c0md3","C":"p = 6m/\u03c0d3","D":"p = 3m/2\u03c0d3"},"answer":"C","explanation":"* Density = mass/volume    *Thevolumeofasphere=43\u03c0(d38)     * Density of a spherical ball of diameter d and mass (m) is given by    \u03c1=m\u00f74\u03c03d38   \u03c1=m\u03c0d36=6m\u03c0d3","marks":"1","difficulty":"3"},{"id":"objective>Physics>2011>3","subject":"Physics","year":"2011","type":"Objective","topic":"FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY","question":"A metal rod of density 7000kgm-3 and cross-sectional area of 0.001257m2 has a mass of 1.76kg. Calculate its length","images":[],"options":{"A":"0.20m","B":"0.25m","C":"0.40m","D":"0.50m"},"answer":"A","explanation":"* Density = 7000 kgm-3    Area(A) = 0.001257m2 = 1.257 x 10-3m2    mass(m) = 1.76kg    length (l) = ?    Recall that,    Density=massvolume=massArea x length(height)    7000=1.761.257 x 10-3 x length   7 x 1.257 x length = 1.76    length=1.768.799=1.768.8    = 0.2m","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>4","subject":"Physics","year":"2011","type":"Objective","topic":"FLUID AT REST : PRESSURE IN FLUIDS","question":"The pressure in a liquid","images":[],"options":{"A":"is the same at all point in the liquid","B":"decreases with depth","C":"is the same in all directions at a given point","D":"is equal to the atmospheric pressure"},"answer":"C","explanation":"The pressure in a liquid is the same in all directions at a given point. This is known as Pascal's law, which states that any change in pressure applied at any point in a fluid is transmitted undiminished to all other points in the fluid.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2011>5","subject":"Physics","year":"2011","type":"Objective","topic":"FLUID AT REST : VISCOSITY (FRICTION IN FLUIDS)","question":"The property of a liquid that is used to determine its suitability as a lubricant is its","images":[],"options":{"A":"capillarity","B":"viscosity","C":"surface tension","D":"relative density"},"answer":"B","explanation":"The property of a liquid that is used to determine its suitability as a lubricant is its viscosity. Viscosity is a measure of a fluid's resistance to flow. It describes the internal friction of a moving fluid. A fluid with large viscosity resists motion because its molecular makeup gives it a lot of internal friction. A fluid with low viscosity flows easily because its molecular makeup results in very little friction when it is in motion.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>6","subject":"Physics","year":"2011","type":"Objective","topic":"MOTION : MOTION UNDER GRAVITY","question":"Which of the following graphs describes a body that accelerates uniformly with an initial velocity greater than zero?","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"C","explanation":"Acceleration is the time rate of increase in velocity of a body.    Mathematically, acceleration=change in velocitytime    This change in velocity is such that the final velocity is greater than the initial velocity.    V2 = V1    \u0394V = V2 - V1    \u0394V = 0    The change in velocity = 0    Acceleration = 0/time = 0.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2011>7","subject":"Physics","year":"2011","type":"Objective","topic":"MOTION : MOTION UNDER GRAVITY","question":"The area under a velocity-time graph represents","images":[],"options":{"A":"final velocity attained","B":"distance covered","C":"acceleration","D":"work done"},"answer":"B","explanation":"* The weight of a body is the gravitational force of attraction experienced by a body.    That is Weight = Gravitational Force.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>8","subject":"Physics","year":"2011","type":"Objective","topic":"MASS AND WEIGHT : DISTINCTION BETWEEN MASS AND WEIGHT","question":"In the absence of gravitational force, the weight of a body is","images":[],"options":{"A":"its mass","B":"zero","C":"its density","D":"its volume"},"answer":"B","explanation":"* The area of a graph is the product of the y-axis of the graph and its x-axis.    * The area under a velocity-time graph, i = velocity x time = distance.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2011>9","subject":"Physics","year":"2011","type":"Objective","topic":"WORK, ENERGY AND POWER : CONCEPT OF ENERGY","question":"A stone of mass 300g is released from rest from the top of a building of height 100m. Determine the kinetic energy gained by the stone when it is quarter way down from the point of release (g = 10ms-2).","images":[],"options":{"A":"750.0J","B":"225.0J","C":"75.0J","D":"22.5J"},"answer":"C","explanation":"* As the body is falling the P.E is decreasing and its K.E increasing.    * At Quarter way down, the PE as reduced by Quarter distance (height) and the K.E has increased.    * At the top of the buildiing K.E = 0    P.E = mgh = 0.3(10)(100) = 300J    At Quarter way down, P.E = 3/4 x 100 x 0.3 x 10 = 225J.    At every point M.E = K.E + P.E which is constant   300 = 225 + K.E    K.E = 75J    At a distance quarter way down from the point of release.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2011>10","subject":"Physics","year":"2011","type":"Objective","topic":"EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES","question":"A body of mass 120g placed at the 10cm mark on a uniform metre rule makes the settle horizontally on a fulcrum placed at the 35cm mark. Calculate the mass of the rule","images":[],"options":{"A":"60g","B":"80g","C":"120g","D":"200g"},"answer":"D","explanation":"* On a uniform metre rule, the weight usually acts at the centre.    *Assume that the length = 100cm        Take moment about the fulcrum    120(25) = 15W    3000 = 15W    W = 200g","marks":"1","difficulty":"3"},{"id":"objective>Physics>2011>11","subject":"Physics","year":"2011","type":"Objective","topic":"SIMPLE HARMONIC MOTION : SIMPLE HARMONIC MOTION (S.H.M)","question":"Two simple pendula A and B of equal lengths and of masses 5g and 20g respectively are located in the same environment. The periods TA and TB of their respective oscillation are related by the equations","images":[],"options":{"A":"TA = 4TB","B":"TA = 1/4TB","C":"TA = TB","D":"TA = 5TB"},"answer":"C","explanation":"* It should be noted that the period of oscillation of a simple pendulum depends on the length of the inextensible string unto which the bob is tied and the acceleration due to gravity.    * This can be deduced from    T = 2\u03c0&radic;l/g&nbsp;    where 'l' is the length of the string and 'g' the acceleration due to gravity.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2011>12","subject":"Physics","year":"2011","type":"Objective","topic":"MOTION : TYPES OF MOTION","question":"An object of mass 5.0kg moves with a velocity of 10ms-1. Calculate its momentum.","images":[],"options":{"A":"50.0kgms-1","B":"15.0kgms-1","C":"2.0kgms-1","D":"0.5kgms-1"},"answer":"A","explanation":"Momentum is calculated by multiplying the mass of an object by its velocity. In this case, the mass is 5.0kg and the velocity is 10ms-1. Therefore, the momentum is 5.0kg * 10ms-1 = 50.0kgms-1.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>13","subject":"Physics","year":"2011","type":"Objective","topic":"PROJECTILE MOTION :","question":"A coin is pushed from the edge of a laboratory bench with a horizontal velocity of 15.0ms-1, if the height of the bench from the floor is 1.5m, calculate the distance from the foot of the bench of the point of impact with the floor. (g = 10ms-2)","images":[],"options":{"A":"0.75m","B":"2.25m","C":"8.22m","D":"15.00m"},"answer":"C","explanation":"Recall that,    x = ut + 1/2gt2    We use 'g' because the body falls under gravity.    * For horizontal direction g = 0    Hence, x = uT, H = 1.5m    T = &radic;2H/g&nbsp;, g = 10ms-2    T = &radic;2(1.5)/10&nbsp;    T = &radic;3/10&nbsp; = &radic;0.3&nbsp;    x = 15&radic;0.3&nbsp; = 8.22m","marks":"1","difficulty":"3"},{"id":"objective>Physics>2011>14","subject":"Physics","year":"2011","type":"Objective","topic":"MACHINES :","question":"Which of the following statements correctly defines a simple machine? A device","images":[],"options":{"A":"that can produce electric current","B":"which can only carry people from one place to another","C":"with which work can be done easily","D":"which changes the state of rest or of uniform motion of an object"},"answer":"C","explanation":"A simple machine is a device that makes work easier. It does this by either changing the direction of a force, increasing the magnitude of a force, or increasing the distance or speed of a force. Therefore, the correct definition of a simple machine is a device with which work can be done easily.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>15","subject":"Physics","year":"2011","type":"Objective","topic":"MACHINES :","question":"The radius of a wheel is 30.0 cm and that of its axle is 6.0 cm. Calculate the effort required to fit a load of 120.0 N using this machine, assuming 100% efficiency","images":[],"options":{"A":"600.0 N","B":"40.0 N","C":"24.0 N","D":"20.0 N"},"answer":"C","explanation":"Since the efficiency is 100%    M.A = V.R    LOADEFFORT=2\u03c0R2\u03c0r \u2192 In a wheel and axle.   lE=Rr   R = 30cm, r = 6cm, L = 120N   120x=306   30x = 720; x = 24N.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>16","subject":"Physics","year":"2011","type":"Objective","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"Which of the following properties is not considered in choosing mercury as a thermometric liquid?","images":[],"options":{"A":"Density","B":"Expansivity","C":"Conductivity","D":"Opacity"},"answer":"A","explanation":"Density s not considered in choosing mercury as a thermometric liquid","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>17","subject":"Physics","year":"2011","type":"Objective","topic":"HEAT ENERGY : BOILING POINT","question":"A hypsometer is used for determining","images":[],"options":{"A":"steam point","B":"relative humidity","C":"ice point","D":"relative density"},"answer":"A","explanation":"A hypsometer measures the boiling point of water, which varies with atmospheric pressure, allowing for the determination of altitude based on the steam point.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>18","subject":"Physics","year":"2011","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"Which of the following statements about anomalous expansion of water are correct?    I. There is contraction between 0oC and 4oC   II. There is expansion between 0oC and 100oC    III. The volume is minimum at 4oC  IV. The volume is maximum at 4 oc","images":[],"options":{"A":"I and II only","B":"II and III only","C":"I and III only","D":"II and IV only"},"answer":"C","explanation":"* Between 0oc and 4oc water behaves in an anomalous way.    * The volume decreases upon increases in temperature between 0oc and 4oc.    * There is a contraction between 0oc and 4oc.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2011>19","subject":"Physics","year":"2011","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"Which of the following equation shows the linear expansivity (\u03b1) and the cubic expansivity (\u03b3) of a material are related?","images":[],"options":{"A":"\u03b3 = \u03b1","B":"\u03b3 = 1 - \u03b1","C":"\u03b3 = 2\u03b1","D":"\u03b3 = 3\u03b1"},"answer":"D","explanation":"The linear expansivity (\u03b1) of a material is a measure of how much a material expands per degree change in temperature. The cubic expansivity (\u03b3) is a measure of how much a material's volume changes with a change in temperature. The relationship between these two quantities is given by the equation \u03b3 = 3\u03b1. Therefore, option 4 is correct.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>20","subject":"Physics","year":"2011","type":"Objective","topic":"HEAT ENERGY : GAS LAWS","question":"Which of the following assumption is not valid for an ideal gas?","images":[],"options":{"A":"Molecules of a particular gas are identical","B":"Molecules move freely throughout the volume of the container","C":"Force of attraction between molecules is negligible","D":"Molecules move at constant speed between collisions"},"answer":"D","explanation":"In the kinetic theory of gases, which describes an ideal gas, there are several assumptions made. These include that the molecules of a particular gas are identical, that they move freely throughout the volume of the container, and that the force of attraction between molecules is negligible. However, it is not assumed that molecules move at a constant speed between collisions. In fact, their speeds are expected to vary due to collisions and the distribution of kinetic energy.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2011>21","subject":"Physics","year":"2011","type":"Objective","topic":"WORK, ENERGY AND POWER : CONCEPT OF POWER","question":"A body is pulled over a distance of 500m by a force of 20 N. if the power developed is 0.4 kW, calculate the time interval during which the force is applied","images":[],"options":{"A":"0.2s","B":"2.5 s","C":"25.0 s","D":"250.0 s"},"answer":"C","explanation":"Power=EnergyTime    Parameters given, F = 20N, d = 500m    P = 0.4KW = 400W    Energy = F x d    = 20 x 500 = 104Nm    Power=EnergyTime    400=1044   400x = 104    4x \u00d7102 = 104    4x = 100    x = 25seconds.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2011>22","subject":"Physics","year":"2011","type":"Objective","topic":"HEAT ENERGY : SPECIFIC HEAT CAPACITY","question":"A metal of mass 200 g at a temperature of 100 oC is placed in 100g of water 25oC in a container of negligible heat capacity. If the final steady temperature is 30 oC, calculate the specific heat capacity of the metal. (Specific heat capacity of water is 4200 Jkg-1 K-1)","images":[],"options":{"A":"150 Jkg-1 K-1)","B":"300 Jkg-1 K-1)","C":"320 Jkg-1 K-1)","D":"1960 Jkg-1 K-1)"},"answer":"A","explanation":"* Heat lost by the metal = Heat gained by the water.    H = mc\u0394\u03b8   Hm = Hw   mwcw(\u0394\u03b8)w = MmCm(\u0394\u03b8)m    mw = 100g , (\u0394\u03b8)w = 5oc    (\u0394\u03b8)m = 70oc   Cw = 4200JKg-1K-1; cm = ?    * 100g = 0.1kg; 200g = 0.1kg    0.1 x 4200 x 5 = 0.2 x cm x 70    0.1 x 21000 = 14cm    cm=210014=150Jkg-1k-1.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2011>23","subject":"Physics","year":"2011","type":"Objective","topic":"HEAT ENERGY : EVAPORATION AND BOILING","question":"Ether produces a cooling effect when it is poured on the hand because it has","images":[],"options":{"A":"low conductivity","B":"high conductivity","C":"high latent heat of vaporization","D":"low latent heat of vaporization"},"answer":"D","explanation":"* It evaporates quickly due to low latent heat of vaporization     * Evaporation results in cooling","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>24","subject":"Physics","year":"2011","type":"Objective","topic":"LIGHT WAVES : PLANE MIRROR","question":"Which of the following statements about the image formed by a plane mirror is not correct?","images":[],"options":{"A":"It is laterally inverted","B":"It has unit magnification","C":"It is formed by actual intersection of rays","D":"Its distance from the mirror is equal to that of the object from the mirror"},"answer":"C","explanation":"The image formed by a plane mirror is a virtual image, which means it is formed by the apparent intersection of light rays, not the actual intersection. A virtual image is an image that appears to be in a location where light does not actually reach. Light does not actually pass through the location on the other side of the mirror; it only appears to an observer as though the light is coming from this location.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2011>25","subject":"Physics","year":"2011","type":"Objective","topic":"LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES","question":"The image formed by a convex mirror is always","images":[],"options":{"A":"real, erect and diminished","B":"real, inverted and diminished","C":"virtual, inverted and diminished","D":"virtual, erect and diminished"},"answer":"D","explanation":"- The image formed by a convex mirror is usually at the back of the mirror (virtual), upright (erect) and smaller than the object (diminished).","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>26","subject":"Physics","year":"2011","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"A ray undergoes a minimum deviation at 40o when it is incident on an equilateral triangular glass prism. Calculate the refraction index of the prism","images":[],"options":{"A":"1.48","B":"1.50","C":"1.53","D":"1.67"},"answer":"C","explanation":"Dm = 40o    A = 60o    n=sin(Dm+A2)\u00f7sin(A2)   n=sin(50)sin30=0.76600.5=1.53.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2011>27","subject":"Physics","year":"2011","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"Total internal refraction occurs in an optical prism when light rays","images":[],"options":{"A":"travel from the prism into an optically denser medium","B":"are incident in the prism at an angle greater than the critical angle","C":"are incident normally in the prism","D":"travel from the prism to air"},"answer":"B","explanation":"Total internal reflection occurs when light travels from a denser medium to a less dense medium (like from glass to air) and hits the boundary at an angle greater than the so-called critical angle. The critical angle is the angle of incidence that provides an angle of refraction of 90-degrees. If the angle of incidence is greater than this critical angle, the light doesn't refract, but instead is totally internally reflected. So, the correct answer is 'are incident in the prism at an angle greater than the critical angle'.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>28","subject":"Physics","year":"2011","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"The speed of light in a certain medium is V while its speed in a vacuum is C. The absolute refractive index of the medium is","images":[],"options":{"A":"C + V","B":"C/V","C":"V/C","D":"C - V"},"answer":"B","explanation":"* The refractive index of a medium is the ratio of the speed of light in vacuum to the speed of light in that medium.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>29","subject":"Physics","year":"2011","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES","question":"An object is placed 20.0 cm in front of a converging lens of focal length 15.0cm. Calculate its image distance.","images":[],"options":{"A":"1.3 cm","B":"8.6 cm","C":"35.0 cm","D":"60.0 cm"},"answer":"D","explanation":"1v=1f-1u  u = 20cm  1v=1f-1u  1v=115-120  1v=20-15300  1v=5300  v = 60cm","marks":"1","difficulty":"3"},{"id":"objective>Physics>2011>30","subject":"Physics","year":"2011","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"Presbyopia is a defect of the eye resulting from","images":[],"options":{"A":"weak ciliary muscles","B":"short eyeball","C":"loss of sphericity of the lens","D":"long eyeball"},"answer":"A","explanation":"Presbyopia is a condition associated with aging in which the eye exhibits a progressively diminished ability to focus on near objects. This happens due to the loss of elasticity of the lens of the eye, which is controlled by the ciliary muscles. As we age, the ciliary muscles become weak and are unable to change the shape of the lens to focus on nearby objects, leading to presbyopia. Therefore, the correct answer is 'weak ciliary muscles'.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>31","subject":"Physics","year":"2011","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"The focal length of the eye-piece of an astronomical telescope is fl. W\u200ehile the focal length of the objective is f2. For normal adjustment, the angular magnification is given by","images":[],"options":{"A":"f2/fl","B":"1 - f2/fl","C":"f2/fl - 1","D":"fl/f2"},"answer":"A","explanation":"Angular magnification = focal length of the objective lens (fo) divided by the focal length of the eyepiece (fe).    M = fo/fe.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2011>32","subject":"Physics","year":"2011","type":"Objective","topic":"SOUND WAVES : BEATS","question":"Two sound waves have frequencies of 12Hz and 10Hz. Calculate their beat period.","images":[],"options":{"A":"0.5 s","B":"1.0 s","C":"1.2 s","D":"2.0 s"},"answer":"A","explanation":"F1 = 12Hz, F2 = 10Hz    Beat = F2 - F1 (Difference in frequencies)    Beat = 12 - 10 = 2Hz    Period = 1/frequency = 1/2 = 0.5s.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>33","subject":"Physics","year":"2011","type":"Objective","topic":"SOUND WAVES : ECHOES AND REVERBERATION","question":"The main difference between echo and reverberation is that","images":[],"options":{"A":"reverberation is reflected sound while echo is refracted sound","B":"the time interval between incident sound and refracted sound is shorter for reverberation","C":"the amplitude of an echo is greater","D":"reverberation is from acoustic speakers while echo comes from clifts"},"answer":"B","explanation":"Echo and reverberation are both phenomena of sound reflection. The main difference between them is the time interval between the original sound and the reflected sound. If this time interval is longer than 0.1 seconds, our brain can distinguish the original sound and the reflected sound as two separate sounds. This is called an echo. If the time interval is less than 0.1 seconds, our brain cannot distinguish them and perceives it as a prolongation of the original sound. This is called reverberation.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>34","subject":"Physics","year":"2011","type":"Objective","topic":"ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM","question":"Which of the following statements about the electromagnetic waves is correct?","images":[],"options":{"A":"Radiowaves have longer frequencies than X-rays","B":"X-rays have the longest wavelength","C":"Some of the waves travel at 3.0 x 108ms-1","D":"While light occupies a region beyond ultraviolet rays"},"answer":"C","explanation":"All electromagnetic waves, including radio waves and X-rays, travel at the speed of light in a vacuum, which is approximately 3.0 x 108 meters per second. This is a fundamental property of electromagnetic waves.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>35","subject":"Physics","year":"2011","type":"Objective","topic":"GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY","question":"The correct relationship between \"G\" and \"g\" in a gravitational field is given by the equation (Where the symbols have their unusual meaning)","images":[],"options":{"A":"g = GM/R","B":"GM/R2","C":"g = GM2/R","D":"g = GM2/R2"},"answer":"B","explanation":"Fg = GMm/R2   Fg = mg;   mg = GMm/R2   g = GM/ R2","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>36","subject":"Physics","year":"2011","type":"Objective","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"The capacitance of a parallel-plate capacitor.","images":[],"options":{"A":"decreases when the separation between the plates decreases","B":"increases when he potential difference between the plates is increased","C":"is greater without a dielectric  material between the plates than with a dielectric","D":"is greater with a dielectric between the plates than without a dielectric"},"answer":"D","explanation":"Capacitance (c) = A\u03b5o / d    where A, \u03b5o and d are area, permitivity of dielectric and distance between the plates respectively. As the permittivity increases (which is as a result of an increase in the dielectric), the capacitance increases.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>37","subject":"Physics","year":"2011","type":"Objective","topic":"ELECTRIC FIELD : ELECTROSTATICS","question":"When the pointed end of an uncharged optical pin is brought near the cap of a positively charged electroscope, it is observed that the gold leaves","images":[],"options":{"A":"collapse slowly","B":"vibrate","C":"are not affected","D":"diverge rapidly"},"answer":"A","explanation":"When the pointed end of an uncharged optical pin is brought near the cap of a positively charged electroscope, the gold leaves collapse slowly. This is because the uncharged pin induces a negative charge on the cap of the electroscope, which neutralizes some of the positive charge, causing the leaves to collapse slowly.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>38","subject":"Physics","year":"2011","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CIRCUIT","question":"Calculate the total charge in the circuit","images":["data:image/png;base64,"],"options":{"A":"80\u00b5C","B":"35\u00b5C","C":"20\u00b5C","D":"16\u00b5C"},"answer":"D","explanation":"Q = CV    Qtotal = CeqXY    2\u03bcF // 6\u03bcF    CT = 2 + 6 = 8\u03bcF    8\u03bcF in series with 2\u03bcF    1cT=18+12=1016   CT=1610=1.6\u03bcC   Qtotal = 1.6 x 10 = 16\u03bcC.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2011>39","subject":"Physics","year":"2011","type":"Objective","topic":"ELECTRIC FIELD : POTENTIAL DIFFERENCE AND ELECTRIC CURRENT","question":"Using the circuit diagram above. Calculate the potential difference across the capacitors in parallel","images":["data:image/png;base64,"],"options":{"A":"10.0 V","B":"8.0 V","C":"6.7 V","D":"2.0 V"},"answer":"D","explanation":"Q = CV    Voltage across the 2\u03bcF capacitance    V=QC=162=8v   Total voltage = 8v + voltage across parallel capacitors.    10 = 8 + x    x = 2v","marks":"1","difficulty":"3"},{"id":"objective>Physics>2011>40","subject":"Physics","year":"2011","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS","question":"Which of the following substances does not conduct electricity?","images":[],"options":{"A":"Graphite","B":"Glass","C":"Sulphuric acid","D":"Table salt solution"},"answer":"B","explanation":"Glass does not conduct electricity. It is an insulator, a material that does not allow the flow of electric current. Other options like Graphite, Sulphuric acid, and Table salt solution are conductors of electricity.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2011>41","subject":"Physics","year":"2011","type":"Objective","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"The unit of capacitance is","images":[],"options":{"A":"Farad","B":"Coulomb","C":"Henry","D":"Ohm"},"answer":"A","explanation":"The unit of capacitance is Farad. Capacitance is the ability of a body to store an electrical charge. It is the ratio of the change in an electric charge in a system to the corresponding change in its electric potential. The standard unit of capacitance in the International System of Units (SI) is the farad (F), which is equal to one coulomb per volt (1 C/V).","marks":"1","difficulty":"1"},{"id":"objective>Physics>2011>42","subject":"Physics","year":"2011","type":"Objective","topic":"ELECTRIC FIELD : SHUNT AND MULTIPLIER","question":"An ammeter with a full scale deflection of 10mA has internal resistance of 0.5\u03a9. Calculate the resistance of the shunt required to adapt it to read up to 3A.","images":[],"options":{"A":"0.0017\u03a9","B":"0.0130\u03a9","C":"0.0250\u03a9","D":"0.1000\u03a9"},"answer":"A","explanation":"To convert a galvanometer to an ammeter. A shunt is applied in parallel to the galvanometer. A shunt is applied in parallel to the galvanometer. Which means the voltage of the shunt will be equal to the voltage of the galvanometer.   Vs = Vg    IsRs = IgRg    Is + Ig = I    Is = I - Ig    (I - Ig)Rs = IgRg    Rs = IgRg/(I - Ig)   Rs = (0.01)(0.5)/3 - 0.01 = 0.0017\u2126","marks":"1","difficulty":"3"},{"id":"objective>Physics>2011>43","subject":"Physics","year":"2011","type":"Objective","topic":"ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY","question":"The resistivity, p, of a material of length l, cross-sectional area A, and resistance R, is given by the equation","images":[],"options":{"A":"p = RA/l","B":"p = l/RA","C":"p = Rl/A","D":"p = R/Al"},"answer":"A","explanation":"R \u03b1 l    R\u03b1lA;   R\u03b1lA;R=klA    k = \u03c1    R=\u03c1lA    RAl=\u03c1","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>44","subject":"Physics","year":"2011","type":"Objective","topic":"ELECTROMAGNETIC FIELD : MOTOR-GENERATOR EFFECT","question":"A wire of length 30 cm is moved with a speed of 2 ms-1 at right angle to a magnetic field of flux density 0.4 T. Calculate the emf induced in the wire.","images":[],"options":{"A":"0.15 V","B":"0.24 V","C":"2.70 V","D":"24.00 V"},"answer":"B","explanation":"Emf = BLVsin\u03b8   v = 2ms-1, l = 0.3m \u03b8 = 90o (at right angles) B = 0.47    Emf = (0.4)(0.3)(2)(1)    = (0.8)(0.3) = 0.24 V","marks":"1","difficulty":"3"},{"id":"objective>Physics>2011>45","subject":"Physics","year":"2011","type":"Objective","topic":"ELECTROMAGNETIC FIELD : POWER TRANSMISSION AND DISTRIBUTION","question":"Which of the following practices will lead to losses in electrical power transmission?","images":[],"options":{"A":"using transmission cable to large diameter","B":"Transmitting at high voltage and low current","C":"Transmitting at relatively low voltage and high current","D":"using a step-up transformer at the production end"},"answer":"C","explanation":"There will be a loss in the electrical power transmission if the transmission is at a low voltage and high current.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>46","subject":"Physics","year":"2011","type":"Objective","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"For photoelectric emission, the threshold frequency is the","images":[],"options":{"A":"maximum frequency of incident radiation that will eject electrons.","B":"minimum frequency of incident radiation required to eject electrons","C":"frequency which results in the emission of the greatest number of electrons.","D":"frequency which impacts greatest kinetic energy to emitted electrons"},"answer":"B","explanation":"In photoelectric emission, the threshold frequency is the minimum frequency of incident radiation required to eject electrons from a material. This is because each material has a certain minimum energy requirement to remove an electron, and this energy is directly proportional to the frequency of the incident radiation according to Planck's equation (E = hf), where h is Planck's constant and f is the frequency of the radiation.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>47","subject":"Physics","year":"2011","type":"Objective","topic":"STRUCTURE OF THE ATOM : X-RAYS","question":"Which of the following is not applicable to X-ray? They","images":[],"options":{"A":"travel in straight lines","B":"travel with speed of light","C":"are deflected by magnetic field","D":"affect photographic films"},"answer":"C","explanation":"X-rays are a type of electromagnetic radiation, just like light rays, but with a much higher energy level. As such, they travel in straight lines and at the speed of light. They can also affect photographic films, which is why they are used in medical imaging. However, unlike charged particles such as electrons or protons, X-rays are not deflected by magnetic fields because they are electrically neutral.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>48","subject":"Physics","year":"2011","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"Uranium - 234 disintegrated to form thorium-230 by emitting","images":[],"options":{"A":"alpha particles","B":"gamma rays","C":"beta negative rays","D":"beta positive rays"},"answer":"A","explanation":"When alpha particle is emitted by an atom it reduces the mass number by '4' and the atomic number by '2'    23492U \u2192 23090T + 42He","marks":"1","difficulty":"2"},{"id":"objective>Physics>2011>49","subject":"Physics","year":"2011","type":"Objective","topic":"WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD","question":"The changes in mass of fuel during a nuclear reactions 2.0 x 10-27 kg. Calculate the amount of energy released. (Speed of light = 3.0 x 108ms-1)","images":[],"options":{"A":"1.8 x 10-10 J","B":"9.0 x 10-11 J","C":"6.0 x 10-19 J","D":"1.2 x 10-45 J"},"answer":"A","explanation":"Energy released (E) = mass X    (speed of light in vacuum)2    E = mc2    E = 2 x 10-27 x 9 x 1011    E = 18 x 10-11    E = 1.8 x 101 x 10-11    E = 1.8 x 10-10J","marks":"1","difficulty":"3"},{"id":"objective>Physics>2011>50","subject":"Physics","year":"2011","type":"Objective","topic":"ENERGY : WORLD ENERGY RESOURCES","question":"Nuclear fusion is not used as a source of energy because","images":[],"options":{"A":"very high temperature is needed for the reaction","B":"the fuel for the reaction is not easy to obtain","C":"less energy is released","D":"the reaction is too slow"},"answer":"A","explanation":"Nuclear fusion is not used as a source of energy because very high temperature is needed for the reaction.","marks":"1","difficulty":"2"}];